import productsData from "../data/ProductData";

const PopularProducts = () => {
  if (!productsData || productsData.length === 0) {
    return <h2 style={{ textAlign: "center" }}>⚠ No products found</h2>;
  }

  const popularItems = productsData.slice(0, 8);

  return (
    <section style={{ padding: "40px" }}>
      <h2 style={{ textAlign: "center", marginBottom: "20px" }}>
        🔥 Popular Products
      </h2>

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(4, 1fr)", // ✅ fixed 4 items per row
          gap: "25px",
          maxWidth: "1200px",
          margin: "0 auto",
        }}
      >
        {popularItems.map((item) => (
          <div key={item.id} style={{ textAlign: "center" }}>
            {/* Image box */}
            <div
              style={{
                border: "1px solid #ddd",
                borderRadius: "10px",
                padding: "15px",
                background: "#d2d2d2ff",
                height: "200px", // ✅ medium box size
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
              }}
            >
              <img
                src={item.image}
                alt={item.name}
                style={{
                  maxWidth: "100%",
                  maxHeight: "180px",
                  objectFit: "contain",
                }}
              />
            </div>

            {/* Product details */}
            <h3 style={{ fontSize: "16px", margin: "10px 0 5px" }}>{item.name}</h3>
            <p style={{ fontSize: "14px", color: "#555" }}>{item.description}</p>
            <p style={{ fontWeight: "bold", margin: "5px 0" }}>${item.price}</p>

            <button
              style={{
                marginTop: "8px",
                padding: "8px 15px",
                border: "none",
                borderRadius: "6px",
                background: "#d9b8a2ff",
                color: "#fff",
                cursor: "pointer",
              }}
            >
              Buy Now
            </button>
          </div>
        ))}
      </div>
    </section>
  );
};

export default PopularProducts;
